                Operador_end = valorOperadorFinal,
                LogicalOperator = " AND "
            };
            // Act
            var resultado = _serviceS.WFiltro(filtro);
            // Assert
            resultado.Should().NotBeNull();
            // Deve usar operador BETWEEN
            resultado.Value.where.Should().Contain($"[{DBDiario2DicInfo.PTabelaNome}].{DBDiario2DicInfo.Operador} BETWEEN @{DBDiario2DicInfo.Operador} AND @{DBDiario2DicInfo.Operador}_end");
            resultado.Value.where.Should().NotContain(" = ");
            // Deve ter exatamente 2 parâmetros
            resultado.Value.parametros.Should().HaveCount(2);
            // Verifica os parâmetros específicos
            var parametroInicial = resultado.Value.parametros.FirstOrDefault(p => p.ParameterName == $"@{DBDiario2DicInfo.Operador}");
            var parametroFinal = resultado.Value.parametros.FirstOrDefault(p => p.ParameterName == $"@{DBDiario2DicInfo.Operador}_end");
            parametroInicial.Should().NotBeNull();
            parametroInicial!.Value.Should().Be(valorOperadorInicial);
            parametroFinal.Should().NotBeNull();
            parametroFinal!.Value.Should().Be(valorOperadorFinal);
        }

