        [Fact]
        public void WFiltro_VistoEqualsIntMinValue_ShouldNotAddParameterOrWhereClause()
        {
            // Arrange
            var filtro = new FilterDiario2
            {
                Visto = int.MinValue
            };
            // Act
            var result = _serviceS.WFiltro(filtro);
            // Assert
            result.Should().NotBeNull();
            result.Value.parametros.Should().NotContain(p => p.ParameterName.Contains(DBDiario2DicInfo.Visto));
            result.Value.where.Should().NotContain(DBDiario2DicInfo.Visto);
        }

        [Fact]
        public void WFiltro_VistoHasValidValue_ShouldAddParameterAndWhereClause()
        {
            // Arrange
            var VistoValue = 1;
            var filtro = new FilterDiario2
            {
                Visto = VistoValue,
                LogicalOperator = " AND "
            };
            // Act
            var result = _serviceS.WFiltro(filtro);
            // Assert
            result.Should().NotBeNull();
            // Check parameter
            var VistoParameter = result.Value.parametros.FirstOrDefault(p => p.ParameterName == $"@{DBDiario2DicInfo.Visto}");
            VistoParameter.Should().NotBeNull();
            VistoParameter.Value.Should().Be(VistoValue);
            // Check where clause
            result.Value.where.Should().Contain($"[{DBDiario2DicInfo.PTabelaNome}].[{DBDiario2DicInfo.Visto}] = @{DBDiario2DicInfo.Visto}");
        }

        [Fact]
        public void WFiltro_VistoWithDifferentValues_ShouldAddCorrectParameterValue()
        {
            // Arrange & Act & Assert for Visto = 0 (typically female)
            var filtroFemale = new FilterDiario2
            {
                Visto = 0
            };
            var resultFemale = _serviceS.WFiltro(filtroFemale);
            resultFemale.Should().NotBeNull();
            var femaleParam = resultFemale.Value.parametros.FirstOrDefault(p => p.ParameterName == $"@{DBDiario2DicInfo.Visto}");
            femaleParam.Should().NotBeNull();
            femaleParam.Value.Should().Be(0);
            // Arrange & Act & Assert for Visto = 1 (typically male)
            var filtroMale = new FilterDiario2
            {
                Visto = 1
            };
            var resultMale = _serviceS.WFiltro(filtroMale);
            resultMale.Should().NotBeNull();
            var maleParam = resultMale.Value.parametros.FirstOrDefault(p => p.ParameterName == $"@{DBDiario2DicInfo.Visto}");
            maleParam.Should().NotBeNull();
            maleParam.Value.Should().Be(1);
        }

